'use client';

import React, { useState, useEffect } from 'react';
import { useRouter }                from 'next/navigation';
import Navbar                       from '../components/Navbar';
import styles                       from '../CSS/editinfo.module.css';

export default function EditInfoPage() {
  const router = useRouter();
  const userId = typeof window !== 'undefined' ? localStorage.getItem('userId') : null;
  const token  = typeof window !== 'undefined' ? localStorage.getItem('token')  : null;

  const [form, setForm]     = useState({ username: '', email: '' });
  const [preview, setPreview] = useState(null);
  const [file, setFile]       = useState(null);
  const [error, setError]     = useState('');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!userId) {
      setError('No user logged in');
      setLoading(false);
      return;
    }
    fetch(`http://localhost:5000/api/auth/user/${userId}`, {
      headers: { Authorization: `Bearer ${token}` }
    })
      .then((r) => r.json())
      .then((u) => {
        if (u.error) throw new Error(u.error);
        setForm({ username: u.username, email: u.email || '' });
        setPreview(u.profilePic || null);
      })
      .catch(() => setError('Failed to load user'))
      .finally(() => setLoading(false));
  }, [userId, token]);

  const handleChange = (e) => {
    setForm((f) => ({ ...f, [e.target.name]: e.target.value }));
  };

  const handleFileChange = (e) => {
    const f = e.target.files?.[0];
    if (f) {
      setFile(f);
      setPreview(URL.createObjectURL(f));
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    if (!userId) {
      setError('No user logged in');
      return;
    }

    const data = new FormData();
    data.append('username', form.username);
    data.append('email', form.email);
    if (file) data.append('profilePic', file);

    try {
      const res = await fetch(`http://localhost:5000/api/auth/update/${userId}`, {
        method: 'PUT',
        headers: { Authorization: `Bearer ${token}` },
        body: data
      });
      const body = await res.json();
      if (!res.ok) throw new Error(body.error || 'Update failed');
      alert('Profile updated!');
      router.push('/UserInfo');
    } catch (err) {
      console.error('Update error:', err);
      setError(err.message);
    }
  };

  if (loading) {
    return (
      <>
        <Navbar />
        <div className={styles.container}>
          <p>Loading...</p>
        </div>
      </>
    );
  }

  return (
    <>
      <Navbar />
      <div className={styles.container}>
        <div className={styles.header}>
          <h2>Edit User Info</h2>
          <button className={styles.saveButton} onClick={handleSubmit}>
            Save Info
          </button>
        </div>
        {error && <p className={styles.error}>{error}</p>}
        <form className={styles.formContainer} onSubmit={handleSubmit}>
          <div className={styles.formGroup}>
            <label>Profile Picture</label>
            {preview ? (
              <img src={preview} className={styles.avatarPreview} alt="avatar" />
            ) : (
              <div className={styles.uploadPlaceholder}>No picture</div>
            )}
            <input type="file" accept="image/*" onChange={handleFileChange} className={styles.fileInput} />
          </div>
          <div className={styles.formGroup}>
            <label>Username</label>
            <input
              name="username"
              type="text"
              value={form.username}
              onChange={handleChange}
              className={styles.input}
            />
          </div>
          <div className={styles.formGroup}>
            <label>Email</label>
            <input
              name="email"
              type="email"
              value={form.email}
              onChange={handleChange}
              className={styles.input}
            />
          </div>
        </form>
      </div>
    </>
  );
}
